queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mode WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTransportation_Mode ?child ; p:hasCity ?parent . } GROUP BY ?child }
  ?child p:type ?mode .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :City } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?mode WHERE {
  ?city_transportation_mode a :City_Transportation_Mode .
  ?transportation_mode a :Transportation_Mode .
  ?city_transportation_mode p:hasTransportation_Mode ?transportation_mode .
  ?city a :City .
  ?city_transportation_mode p:hasCity ?city .
  ?city p:name ?name .
  ?transportation_mode p:type ?mode .
} }
  collective: { SELECT ?mode WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTransportation_Mode ?child ; p:hasCity ?parent . } GROUP BY ?child }
  ?child p:type ?mode .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :City } }
  FILTER(?nf = ?total)
} }
}
